const body = $json;
let text=''; try { text=(body.content||[]).filter(b=>b.type==='text').map(b=>b.text).join(''); } catch(e){}
let parsed; try { parsed=JSON.parse((text||'').replace(/```json|```/g,'').trim()); } catch(e){ parsed={classification:'unclear',reasoning:'parse_failed',urgency:'normal'}; }
const valid=['interested','objection','not_interested','unclear','auto_reply'];
if(!valid.includes(parsed.classification)) parsed.classification='unclear';
if(!['high','normal','low'].includes(parsed.urgency)) parsed.urgency='normal';
return [{ json: { from_email: $('Prep Reply').item.json.from_email, reply_text: $('Prep Reply').item.json.reply_text, classification: parsed.classification, reasoning: (parsed.reasoning||'').slice(0,300), urgency: parsed.urgency } }];
